           &amp;quot;wedding&amp;quot;, &amp;quot;diving&amp;quot;, &amp;quot;rapeseed&amp;quot;, &amp;quot;daisy&amp;quot;, &amp;quot;plant&amp;quot;, &amp;quot;corn&amp;quot;, &amp;quot;pinecone&amp;quot;, &amp;quot;chestnut&amp;quot;, &amp;quot;mushroom&amp;quot;, &amp;quot;corn&amp;quot;, &amp;quot;toilet paper&amp;quot;,
           &amp;quot;woman&amp;quot;, &amp;quot;man&amp;quot;
] # 类名

your_idea_text = &amp;quot;a car&amp;quot;     # 你对这张图片的辨别。
my_text.append(your_idea_text)

text_token = clip.tokenize(my_text).to(device)
with torch.no_grad():
    image_features = model.encode_image(image)
    text_features = model.encode_text(text_token)

    logits_per_image, logits_per_text = model(image, text_token)
    probs = logits_per_image.softmax(dim=-1).cpu().numpy()

print(&amp;quot;A photo of &amp;quot; + my_text[list(probs[0]).index(max(probs[0]))])
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;效果&#34;&gt;&lt;a href=&#34;#效果&#34; class=&#34;headerlink&#34; title=&#34;效果&#34;&gt;&lt;/a&gt;效果&lt;/h3&gt;&lt;p&gt;以这张图片为例：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/clip6.jpg&#34; alt=&#34;image&#34;&gt;&lt;/p&gt;
&lt;p&gt;运行代码后，识别出的图片内容：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/clip5.png&#34; alt=&#34;image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;探索代码&#34;&gt;&lt;a href=&#34;#探索代码&#34; class=&#34;headerlink&#34; title=&#34;探索代码&#34;&gt;&lt;/a&gt;探索代码&lt;/h2&gt;&lt;p&gt;可以发现总代码的&lt;code&gt;image_features&lt;/code&gt;和&lt;code&gt;text_features&lt;/code&gt;并没有用上。其实，&lt;code&gt;image_features&lt;/code&gt;是所有图像特征的集合，&lt;code&gt;text_features&lt;/code&gt;是所有文本标签的特征集合。可以用&lt;code&gt;PCA&lt;/code&gt;主成分分析法可视化出来。为了简便，删除大部分&lt;code&gt;my_text&lt;/code&gt;文本标签，只保留若干个标签。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;my_text = [&amp;quot;fish&amp;quot;, &amp;quot;cock&amp;quot;, &amp;quot;hen&amp;quot;, &amp;quot;ostrich&amp;quot;, &amp;quot;bird&amp;quot;, &amp;quot;hawk&amp;quot;, &amp;quot;gecko&amp;quot;, &amp;quot;toad&amp;quot;, &amp;quot;frog&amp;quot;]
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;依然，你的猜测是：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;your_idea_text = &amp;quot;a car&amp;quot;     # 你对这张图片的辨别。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;导入相关包：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;from sklearn.decomposition import PCA
import matplotlib.pyplot as plt
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;先将图像特征和文本特征拼接到一起方便处理：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;all_features = torch.cat([image_features, text_features], dim=0).cpu().numpy()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;建立模型，处理图像特征和文本特征，将高维特征映射到二维平面特征：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;pca = PCA(n_components=2)
features_2d = pca.fit_transform(all_features)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可视化，首先将图像的特征打点：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;plt.figure(figsize=(10, 10))
plt.scatter(features_2d[0, 0], features_2d[0, 1], color=&amp;#39;red&amp;#39;, label=&amp;#39;Image Feature&amp;#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;接下来打点文本特征：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;for i, text in enumerate(my_text):
    plt.scatter(features_2d[i+1, 0], features_2d[i+1, 1], label=f&amp;#39;Text Feature: &amp;#123;text&amp;#125;&amp;#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;显示图例，横纵轴标签等，并最终显示：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;plt.legend()
plt.title(&amp;quot;PCA of Image and Text Features&amp;quot;)
plt.xlabel(&amp;quot;PCA Component 1&amp;quot;)
plt.ylabel(&amp;quot;PCA Component 2&amp;quot;)
plt.show()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可视化图像为：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/clip7.png&#34; alt=&#34;image&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们丰富一下猜测的文本：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;your_idea_text = &amp;quot;a racing car with road-blocks&amp;quot;     # 你对这张图片的识别。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可视化出来可以看到猜测的文本特征与图像特征更接近了：&lt;br&gt;&lt;img data-src=&#34;../../assets/clip8.png&#34; alt=&#34;image&#34;&gt;&lt;/p&gt;
&lt;p&gt;更进一步的丰富，加上了路障的颜色以及车子在地上的描述：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;lang-python&#34;&gt;your_idea_text = &amp;quot;a racing car on the floor with some red and blue road-blocks besides&amp;quot;     # 你对这张图片的识别。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可视化出来，可见猜测的文本在横轴的数值在这次的修改超过了5，进一步向图像特征接近：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/clip9.png&#34; alt=&#34;image&#34;&gt;&lt;/p&gt;
&lt;p&gt;[这也就说明，跨模态的信息可以被统一地映射到同一个特征空间进行学习，这就为多模态的研究开辟了道路]{.red}&lt;/p&gt;
